import{_ as d,o as r,c as a,a2 as h}from"./chunks/framework.B72_uj9U.js";const A=JSON.parse('{"title":"服装行业供应商自评问卷（SAQ-GAR-001）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/garment/saq.md","filePath":"zh/industry/garment/saq.md"}'),e={name:"zh/industry/garment/saq.md"};function o(b,t,l,n,_,i){return r(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="服装行业供应商自评问卷-saq-gar-001" tabindex="-1">服装行业供应商自评问卷（SAQ-GAR-001） <a class="header-anchor" href="#服装行业供应商自评问卷-saq-gar-001" aria-label="Permalink to &quot;服装行业供应商自评问卷（SAQ-GAR-001）&quot;">​</a></h1><blockquote><p><strong>版本：</strong> 2025年版 · <strong>适用范围：</strong> 服装、纺织、鞋类及配件制造商</p><p><strong>填写说明：</strong> 本问卷供制造型工厂填写。请如实回答——虚假陈述将导致合同终止，并可能影响您的行业信誉记录。所有&quot;否&quot;或&quot;部分&quot;答案无需隐瞒，但须在备注栏说明整改计划及时间表。</p></blockquote><hr><p><strong>供应商信息</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>填写</th></tr></thead><tbody><tr><td>工厂法人名称</td><td></td></tr><tr><td>工厂实际生产地址</td><td></td></tr><tr><td>总部（若与工厂不同）</td><td></td></tr><tr><td>主要联系人姓名 / 职务</td><td></td></tr><tr><td>联系电话 / 邮件</td><td></td></tr><tr><td>工厂成立年份</td><td></td></tr><tr><td>本厂员工总数（含派遣）</td><td></td></tr><tr><td>主要生产品类</td><td></td></tr><tr><td>当前有效认证（SA8000 / BSCI / WRAP 等）</td><td></td></tr><tr><td>填表人签名 / 日期</td><td></td></tr></tbody></table><hr><h2 id="第一部分-劳工与工作条件" tabindex="-1">第一部分　劳工与工作条件 <a class="header-anchor" href="#第一部分-劳工与工作条件" aria-label="Permalink to &quot;第一部分　劳工与工作条件&quot;">​</a></h2><h3 id="a1-工时与加班" tabindex="-1">A1　工时与加班 <a class="header-anchor" href="#a1-工时与加班" aria-label="Permalink to &quot;A1　工时与加班&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>A1.1</td><td>普通周（非旺季）平均工时是否≤60小时？</td><td></td><td></td><td></td><td></td></tr><tr><td>A1.2</td><td>所有加班是否为工人自愿，且有书面/电子记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>A1.3</td><td>工人是否有权在不受处罚的情况下拒绝加班？</td><td></td><td></td><td></td><td></td></tr><tr><td>A1.4</td><td>连续工作7天后，工人是否获得至少1天休息？</td><td></td><td></td><td></td><td></td></tr><tr><td>A1.5</td><td>旺季最高工时记录是否≤每月288小时（含加班）？</td><td></td><td></td><td></td><td></td></tr><tr><td>A1.6</td><td>工时记录是否为原始电子打卡数据（非手工修改）？</td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="a2-工资与福利" tabindex="-1">A2　工资与福利 <a class="header-anchor" href="#a2-工资与福利" aria-label="Permalink to &quot;A2　工资与福利&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>A2.1</td><td>基本工资是否≥当地法定最低工资？</td><td></td><td></td><td></td><td></td></tr><tr><td>A2.2</td><td>加班费是否按法定倍率支付（平日1.5×、周末2×、法定节假日3×）？</td><td></td><td></td><td></td><td></td></tr><tr><td>A2.3</td><td>工资是否按时足额发放，无不合理扣押或拖欠？</td><td></td><td></td><td></td><td></td></tr><tr><td>A2.4</td><td>工资单是否以工人可理解的语言提供，列明各项明细？</td><td></td><td></td><td></td><td></td></tr><tr><td>A2.5</td><td>是否为所有正式员工缴纳法定社会保险（养老、医疗、工伤等）？</td><td></td><td></td><td></td><td></td></tr><tr><td>A2.6</td><td>从工资中扣除的餐费、住宿费是否有事先书面告知？</td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="a3-强迫劳动与债务束缚" tabindex="-1">A3　强迫劳动与债务束缚 <a class="header-anchor" href="#a3-强迫劳动与债务束缚" aria-label="Permalink to &quot;A3　强迫劳动与债务束缚&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>A3.1</td><td>是否向工人收取任何形式的招募费或押金？</td><td></td><td></td><td></td><td></td></tr><tr><td>A3.2</td><td>工人的身份证件（护照、身份证等）是否由工人本人保管？</td><td></td><td></td><td></td><td></td></tr><tr><td>A3.3</td><td>工人是否可以在任何时候（给予合理通知后）自由离职？</td><td></td><td></td><td></td><td></td></tr><tr><td>A3.4</td><td>是否使用任何形式的监控或限制措施阻止工人自由移动（宿舍锁闭、通行证限制等）？</td><td></td><td></td><td></td><td></td></tr><tr><td>A3.5</td><td>外籍劳工（如有）的招募渠道是否经过尽职调查（排除债务束缚型中介）？</td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="a4-童工与未成年工" tabindex="-1">A4　童工与未成年工 <a class="header-anchor" href="#a4-童工与未成年工" aria-label="Permalink to &quot;A4　童工与未成年工&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>A4.1</td><td>所有员工是否≥16周岁？</td><td></td><td></td><td></td><td></td></tr><tr><td>A4.2</td><td>16–18周岁员工（如有）是否被安排在不违反当地法律的轻体力岗位，且不从事夜班？</td><td></td><td></td><td></td><td></td></tr><tr><td>A4.3</td><td>入职时是否核验年龄证明文件并留存副本？</td><td></td><td></td><td></td><td></td></tr><tr><td>A4.4</td><td>是否有书面的年龄核验程序？</td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="a5-工会与集体谈判" tabindex="-1">A5　工会与集体谈判 <a class="header-anchor" href="#a5-工会与集体谈判" aria-label="Permalink to &quot;A5　工会与集体谈判&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>A5.1</td><td>工人是否有权自由组建或加入工会（在当地法律允许范围内）？</td><td></td><td></td><td></td><td></td></tr><tr><td>A5.2</td><td>是否存在针对工会成员的歧视、恐吓或解雇行为？</td><td></td><td></td><td></td><td></td></tr><tr><td>A5.3</td><td>在工会受限的地区，是否建立了替代性工人代表机制（工人委员会等）？</td><td></td><td></td><td></td><td></td></tr><tr><td>A5.4</td><td>工人代表是否可以在不受管理层在场的情况下与工人私下沟通？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="第二部分-建筑与消防安全" tabindex="-1">第二部分　建筑与消防安全 <a class="header-anchor" href="#第二部分-建筑与消防安全" aria-label="Permalink to &quot;第二部分　建筑与消防安全&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>B1</td><td>工厂建筑是否持有有效的使用许可证，且实际用途与许可证一致？</td><td></td><td></td><td></td><td></td></tr><tr><td>B2</td><td>过去5年内是否进行过由持证工程师出具的建筑结构安全评估？</td><td></td><td></td><td></td><td></td></tr><tr><td>B3</td><td>重型设备（发电机、压缩机）安装是否有结构承重评估？</td><td></td><td></td><td></td><td></td></tr><tr><td>B4</td><td>是否有充足的疏散通道，且在生产时段保持畅通？</td><td></td><td></td><td></td><td></td></tr><tr><td>B5</td><td>消防设施（灭火器、喷淋、报警器）是否定期检测，有效期内？</td><td></td><td></td><td></td><td></td></tr><tr><td>B6</td><td>过去12个月内是否进行过消防演练，并有记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>B7</td><td>所有应急出口是否有清晰标识，且在工作时间不上锁？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="第三部分-化学品管理-纺织加工工厂适用" tabindex="-1">第三部分　化学品管理（纺织加工工厂适用） <a class="header-anchor" href="#第三部分-化学品管理-纺织加工工厂适用" aria-label="Permalink to &quot;第三部分　化学品管理（纺织加工工厂适用）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>C1</td><td>是否维护化学品清单，包含所有在用染料、助剂、溶剂？</td><td></td><td></td><td></td><td></td></tr><tr><td>C2</td><td>所有化学品是否有安全数据表（SDS/MSDS），工人可随时查阅？</td><td></td><td></td><td></td><td></td></tr><tr><td>C3</td><td>是否已排除 ZDHC MRSL（制造业限制物质清单）中的禁用物质？</td><td></td><td></td><td></td><td></td></tr><tr><td>C4</td><td>是否对废水进行定期检测，并符合当地排放标准？</td><td></td><td></td><td></td><td></td></tr><tr><td>C5</td><td>染整废水是否经处理设施处理后排放（非直接排入市政管网或自然水体）？</td><td></td><td></td><td></td><td></td></tr><tr><td>C6</td><td>危险化学品废物是否由持证单位处理，并保留转移联单？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="第四部分-分包与供应链透明度" tabindex="-1">第四部分　分包与供应链透明度 <a class="header-anchor" href="#第四部分-分包与供应链透明度" aria-label="Permalink to &quot;第四部分　分包与供应链透明度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>D1</td><td>是否将本采购方的订单（全部或部分）转包给第三方工厂？</td><td></td><td></td><td></td><td></td></tr><tr><td>D2</td><td>如是：所有分包工厂是否经采购方书面批准？</td><td></td><td></td><td></td><td></td></tr><tr><td>D3</td><td>所有分包工厂的地址和联系方式是否完整提供给采购方？</td><td></td><td></td><td></td><td></td></tr><tr><td>D4</td><td>分包工厂是否接受与本工厂相同标准的审核要求？</td><td></td><td></td><td></td><td></td></tr><tr><td>D5</td><td>原材料（面料、辅料）的主要供应商名单是否可提供？</td><td></td><td></td><td></td><td></td></tr><tr><td>D6</td><td>是否使用来自中国新疆的棉花或棉纱？</td><td></td><td></td><td></td><td></td></tr><tr><td>D7</td><td>如否：是否保留原棉采购溯源文件，可供审核？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="第五部分-管理体系与合规文件" tabindex="-1">第五部分　管理体系与合规文件 <a class="header-anchor" href="#第五部分-管理体系与合规文件" aria-label="Permalink to &quot;第五部分　管理体系与合规文件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>是否具备</th><th>最新版本日期</th><th>备注</th></tr></thead><tbody><tr><td>工厂营业执照</td><td></td><td></td><td></td></tr><tr><td>建筑使用许可证</td><td></td><td></td><td></td></tr><tr><td>消防验收证明</td><td></td><td></td><td></td></tr><tr><td>环保排污许可证</td><td></td><td></td><td></td></tr><tr><td>工人劳动合同样本（含派遣）</td><td></td><td></td><td></td></tr><tr><td>工资发放记录（近12个月）</td><td></td><td></td><td></td></tr><tr><td>出勤打卡记录（近12个月）</td><td></td><td></td><td></td></tr><tr><td>社保缴纳证明</td><td></td><td></td><td></td></tr><tr><td>危险化学品经营/使用许可</td><td></td><td></td><td></td></tr><tr><td>SA8000 / BSCI / WRAP 认证书（如有）</td><td></td><td></td><td></td></tr><tr><td>最近一次外部审核报告</td><td></td><td></td><td></td></tr><tr><td>CAP整改计划（如有未关闭项）</td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="第六部分-整改承诺" tabindex="-1">第六部分　整改承诺 <a class="header-anchor" href="#第六部分-整改承诺" aria-label="Permalink to &quot;第六部分　整改承诺&quot;">​</a></h2><p>针对上述任何&quot;否&quot;或&quot;部分&quot;答案，请在下方说明整改计划：</p><table tabindex="0"><thead><tr><th>问题编号</th><th>当前状态</th><th>计划措施</th><th>预计完成日期</th><th>负责人</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><p><strong>授权签署</strong></p><p>本工厂声明，上述答案真实、准确、完整。</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>工厂法人代表签字</td><td>__________________</td></tr><tr><td>职务</td><td>__________________</td></tr><tr><td>日期</td><td>__________________</td></tr><tr><td>公章</td><td></td></tr></tbody></table>',37)])])}const u=d(e,[["render",o]]);export{A as __pageData,u as default};
